// Build the 4 canary tickets — one per strategic routine. Known-good prompts
// designed to produce a short, cheap deliverable. TEAM_ID must match the Agent Team
// team in Linear (env: LINEAR_TEAM_ID).
const now = new Date().toISOString().slice(0, 10);
const canaries = [
  { typeLabel: 'type:architect', routine: 'Technical Architect', title: `[Canary ${now}] Should we adopt Python 3.13 for new services?`, prompt: 'Produce a 2-paragraph ADR draft on whether new services should adopt Python 3.13. Include one risk and one opportunity. Keep it under 400 words.' },
  { typeLabel: 'type:analyst', routine: 'Analyst', title: `[Canary ${now}] Competitive snapshot — one prototype`, prompt: 'Produce a 3-bullet competitive snapshot for the Recipe Remix prototype. Focus on whitespace vs. 1-2 named competitors. Keep it under 300 words.' },
  { typeLabel: 'type:ux', routine: 'User Researcher', title: `[Canary ${now}] Usability heuristic — richezamor.com homepage`, prompt: 'Do a 3-point Nielsen heuristic scan of the richezamor.com homepage. Flag the single highest-severity finding. Under 300 words.' },
  { typeLabel: 'type:research', routine: 'AI Researcher', title: `[Canary ${now}] Method eval — prompt caching for SIA consolidation`, prompt: 'Give a short adopt/trial/hold recommendation on whether SIA\'s consolidation pipeline should use Anthropic prompt caching. 3 bullets of rationale. Under 300 words.' },
];
return canaries.map(c => ({ json: { ...c, canaryDate: now } }));

