// Extract the created issue id + identifier so we can flip its state next.
const in0 = $('Build canary tickets').item.json;
const resp = $input.first().json;
const issue = resp?.data?.issueCreate?.issue;
if (!issue) throw new Error(`issueCreate failed: ${JSON.stringify(resp).slice(0, 300)}`);
return [{ json: { ...in0, issueId: issue.id, issueIdentifier: issue.identifier, issueUrl: issue.url } }];

