// Evaluate the canary: did n8n fire the routine? Did the routine complete?
const in0 = $('Capture issue id').item.json;
const resp = $input.first().json;
const comments = resp?.data?.issue?.comments?.nodes || [];
const bodies = comments.map(c => c.body || '');
const fired = bodies.some(b => /routine fired/i.test(b));
const complete = bodies.some(b => /✓.*complete|✓ complete/i.test(b));
const notion = bodies.some(b => /notion\.so|notion\.site/i.test(b));

const missing = [];
if (!fired) missing.push('fire');
if (!complete) missing.push('complete');
if (!notion) missing.push('notion-artifact');

return [{
  json: {
    ...in0,
    fired,
    complete,
    notion,
    missing,
    healthy: missing.length === 0,
  }
}];
